composer require laravel/breeze --dev 2>&1 | tail -3
</boltAction>

<boltAction type="shell">
php artisan breeze:install blade 2>&1 | tail -5
</boltAction>

<boltAction type="shell">
npm install 2>&1 | tail -3
</boltAction>

