<?php

namespace App\Providers;

use App\Services\Providers\WeatherProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\SpeciesInfoProviderInterface;
use App\Services\Providers\DemoWeatherProvider;
use App\Services\Providers\DemoTideProvider;
use App\Services\Providers\DemoSpeciesInfoProvider;
use Illuminate\Support\Facades\Gate;
use Illuminate\Support\ServiceProvider;

class AppServiceProvider extends ServiceProvider
{
    public function register(): void
    {
        // Bind provider interfaces
        $this->app->bind(WeatherProviderInterface::class, function () {
            return match (config('services.weather.provider', 'demo')) {
                default => new DemoWeatherProvider(),
            };
        });

        $this->app->bind(TideProviderInterface::class, function () {
            return match (config('services.tides.provider', 'demo')) {
                default => new DemoTideProvider(),
            };
        });

        $this->app->bind(SpeciesInfoProviderInterface::class, function () {
            return match (config('services.species.provider', 'demo')) {
                default => new DemoSpeciesInfoProvider(),
            };
        });
    }

    public function boot(): void
    {
        // Define gates based on permissions
        Gate::before(function ($user, $ability) {
            if ($user->isAdmin()) {
                return true;
            }
        });

        Gate::define('manage-users', fn($user) => $user->hasPermission('manage-users'));
        Gate::define('manage-roles', fn($user) => $user->hasPermission('manage-roles'));
        Gate::define('manage-settings', fn($user) => $user->hasPermission('manage-settings'));
        Gate::define('moderate-content', fn($user) => $user->hasPermission('moderate-content'));
        Gate::define('delete-any-post', fn($user) => $user->hasPermission('delete-any-post'));
        Gate::define('delete-any-comment', fn($user) => $user->hasPermission('delete-any-comment'));
        Gate::define('review-reports', fn($user) => $user->hasPermission('review-reports'));
        Gate::define('create-post', fn($user) => $user->hasPermission('create-post'));
        Gate::define('create-hunt', fn($user) => $user->hasPermission('create-hunt'));
        Gate::define('create-comment', fn($user) => $user->hasPermission('create-comment'));
        Gate::define('like-post', fn($user) => $user->hasPermission('like-post'));
    }
}
