<boltAction type="file" filePath="app/Http/Controllers/PostController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\Post;
use App\Models\PostImage;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Storage;

class PostController extends Controller
{
    public function create()
    {
        $this->authorize('create', Post::class);
        return view('posts.create');
    }

    public function store(Request $request)
    {
        $this->authorize('create', Post::class);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:5000',
            'location_name' => 'nullable|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'location_privacy' => 'in:exact,approximate',
            'species' => 'nullable|string|max:100',
            'bait_used' => 'nullable|string|max:255',
            'gear_notes' => 'nullable|string|max:2000',
            'weight_kg' => 'nullable|numeric|min:0|max:999',
            'length_cm' => 'nullable|numeric|min:0|max:9999',
            'caught_at' => 'nullable|date|before_or_equal:now',
            'images' => 'required|array|min:1|max:5',
            'images.*' => 'image|mimes:jpeg,jpg,png,webp|max:10240',
        ]);

        $post = DB::transaction(function () use ($validated, $request) {
            $post = $request->user()->posts()->create($validated);

            if ($request->hasFile('images')) {
                foreach ($request->file('images') as $index => $image) {
                    $path = $image->store('posts/' . $post->id, 'public');

                    // Generate thumbnail
                    $thumbnailPath = null;
                    if (function_exists('imagecreatefromjpeg')) {
                        $thumbnailPath = $this->createThumbnail($image, $post->id);
                    }

                    PostImage::create([
                        'post_id' => $post->id,
                        'path' => $path,
                        'thumbnail_path' => $thumbnailPath,
                        'sort_order' => $index,
                    ]);
                }
            }

            return $post;
        });

        return redirect()->route('posts.show', $post)->with('success', 'Catch posted! 🎣');
    }

    public function show(Post $post)
    {
        $this->authorize('view', $post);

        $post->load(['user', 'images', 'comments.user', 'likes']);

        return view('posts.show', compact('post'));
    }

    public function edit(Post $post)
    {
        $this->authorize('update', $post);
        return view('posts.edit', compact('post'));
    }

    public function update(Request $request, Post $post)
    {
        $this->authorize('update', $post);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:5000',
            'location_name' => 'nullable|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'location_privacy' => 'in:exact,approximate',
            'species' => 'nullable|string|max:100',
            'bait_used' => 'nullable|string|max:255',
            'gear_notes' => 'nullable|string|max:2000',
            'weight_kg' => 'nullable|numeric|min:0|max:999',
            'length_cm' => 'nullable|numeric|min:0|max:9999',
            'caught_at' => 'nullable|date|before_or_equal:now',
        ]);

        $post->update($validated);

        return redirect()->route('posts.show', $post)->with('success', 'Post updated!');
    }

    public function destroy(Post $post)
    {
        $this->authorize('delete', $post);

        // Delete images from storage
        foreach ($post->images as $image) {
            Storage::disk('public')->delete($image->path);
            if ($image->thumbnail_path) {
                Storage::disk('public')->delete($image->thumbnail_path);
            }
        }

        $post->delete();

        return redirect()->route('feed')->with('success', 'Post deleted.');
    }

    public function toggleVisibility(Post $post)
    {
        $this->authorize('hide', $post);

        $post->update(['is_visible' => !$post->is_visible]);

        return back()->with('success', $post->is_visible ? 'Post made visible.' : 'Post hidden.');
    }

    private function createThumbnail($image, $postId): ?string
    {
        try {
            $sourcePath = $image->getPathname();
            $mime = $image->getMimeType();

            $source = match ($mime) {
                'image/jpeg', 'image/jpg' => imagecreatefromjpeg($sourcePath),
                'image/png' => imagecreatefrompng($sourcePath),
                'image/webp' => imagecreatefromwebp($sourcePath),
                default => null,
            };

            if (!$source) return null;

            $origW = imagesx($source);
            $origH = imagesy($source);
            $thumbW = 400;
            $thumbH = (int) ($origH * ($thumbW / $origW));

            $thumb = imagecreatetruecolor($thumbW, $thumbH);
            imagecopyresampled($thumb, $source, 0, 0, 0, 0, $thumbW, $thumbH, $origW, $origH);

            $thumbDir = storage_path('app/public/posts/' . $postId . '/thumbs');
            if (!is_dir($thumbDir)) {
                mkdir($thumbDir, 0755, true);
            }

            $thumbFilename = 'thumb_' . uniqid() . '.jpg';
            $thumbFullPath = $thumbDir . '/' . $thumbFilename;
            imagejpeg($thumb, $thumbFullPath, 80);

            imagedestroy($source);
            imagedestroy($thumb);

            return 'posts/' . $postId . '/thumbs/' . $thumbFilename;
        } catch (\Exception $e) {
            return null;
        }
    }
}
</boltAction>

