<?php

namespace App\Http\Controllers;

use App\Models\Hunt;
use App\Models\HuntChecklistItem;
use App\Services\HuntBriefingService;
use Illuminate\Http\Request;

class HuntController extends Controller
{
    public function __construct(private HuntBriefingService $briefingService) {}

    public function index(Request $request)
    {
        $hunts = $request->user()->hunts()
            ->orderBy('starts_at', 'desc')
            ->paginate(12);

        return view('hunts.index', compact('hunts'));
    }

    public function create()
    {
        $this->authorize('create', Hunt::class);
        return view('hunts.create');
    }

    public function store(Request $request)
    {
        $this->authorize('create', Hunt::class);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'location_name' => 'required|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'country' => 'string|max:100',
            'region' => 'nullable|string|max:100',
            'is_coastal' => 'boolean',
            'starts_at' => 'required|date|after:now',
            'ends_at' => 'required|date|after:starts_at',
            'notes' => 'nullable|string|max:5000',
            'is_public' => 'boolean',
        ]);

        $validated['is_coastal'] = $request->boolean('is_coastal');
        $validated['is_public'] = $request->boolean('is_public');

        $hunt = $request->user()->hunts()->create($validated);

        // Generate briefing
        $this->briefingService->generateBriefing($hunt);

        return redirect()->route('hunts.show', $hunt)->with('success', 'Hunt planned! Check your briefing below. 🗺️');
    }

    public function show(Hunt $hunt)
    {
        $this->authorize('view', $hunt);

        $hunt->load(['checklistItems', 'briefing', 'user']);

        // Regenerate briefing if expired
        if (!$hunt->briefing || $hunt->briefing->isExpired()) {
            $this->briefingService->generateBriefing($hunt);
            $hunt->load(['checklistItems', 'briefing']);
        }

        $checklistByCategory = $hunt->checklistItems->groupBy('category');

        return view('hunts.show', compact('hunt', 'checklistByCategory'));
    }

    public function edit(Hunt $hunt)
    {
        $this->authorize('update', $hunt);
        return view('hunts.edit', compact('hunt'));
    }

    public function update(Request $request, Hunt $hunt)
    {
        $this->authorize('update', $hunt);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'location_name' => 'required|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'country' => 'string|max:100',
            'region' => 'nullable|string|max:100',
            'is_coastal' => 'boolean',
            'starts_at' => 'required|date',
            'ends_at' => 'required|date|after:starts_at',
            'notes' => 'nullable|string|max:5000',
            'is_public' => 'boolean',
        ]);

        $validated['is_coastal'] = $request->boolean('is_coastal');
        $validated['is_public'] = $request->boolean('is_public');

        $hunt->update($validated);

        // Regenerate briefing
        $this->briefingService->generateBriefing($hunt);

        return redirect()->route('hunts.show', $hunt)->with('success', 'Hunt updated!');
    }

    public function destroy(Hunt $hunt)
    {
        $this->authorize('delete', $hunt);
        $hunt->delete();
        return redirect()->route('hunts.index')->with('success', 'Hunt deleted.');
    }

    public function toggleChecklist(Request $request, HuntChecklistItem $item)
    {
        $hunt = $item->hunt;
        $this->authorize('update', $hunt);

        $item->update(['is_checked' => !$item->is_checked]);

        if ($request->ajax()) {
            return response()->json(['checked' => $item->is_checked]);
        }

        return back();
    }

    public function refreshBriefing(Hunt $hunt)
    {
        $this->authorize('update', $hunt);

        // Force refresh by clearing cache
        \Illuminate\Support\Facades\Cache::forget("hunt_briefing_{$hunt->id}");
        if ($hunt->briefing) {
            $hunt->briefing->update(['expires_at' => now()->subMinute()]);
        }

        $this->briefingService->generateBriefing($hunt);

        return redirect()->route('hunts.show', $hunt)->with('success', 'Briefing refreshed!');
    }

    public function shared(string $token)
    {
        $hunt = Hunt::where('share_token', $token)->firstOrFail();

        if (!$hunt->is_public) {
            abort(404);
        }

        $hunt->load(['checklistItems', 'briefing', 'user']);
        $checklistByCategory = $hunt->checklistItems->groupBy('category');

        return view('hunts.shared', compact('hunt', 'checklistByCategory'));
    }
}
</boltAction>

