use App\Http\Controllers\Admin\UserManagementController;
use App\Http\Controllers\Admin\ReportManagementController;
use App\Http\Controllers\Admin\RolePermissionController;
use Illuminate\Support\Facades\Route;

// Public feed
Route::get('/', [FeedController::class, 'index'])->name('feed');

// Shared hunt (public)
Route::get('/hunt/shared/{token}', [HuntController::class, 'shared'])->name('hunts.shared');

// Public profile
Route::get('/profile/{user}', [ProfileController::class, 'show'])->name('profile.show');

// Auth required routes
Route::middleware(['auth', 'verified'])->group(function () {
    // Profile
    Route::get('/settings/profile', [ProfileController::class, 'edit'])->name('profile.edit');
    Route::put('/settings/profile', [ProfileController::class, 'update'])->name('profile.update');

    // Posts
    Route::get('/posts/create', [PostController::class, 'create'])->name('posts.create');
    Route::post('/posts', [PostController::class, 'store'])->name('posts.store');
    Route::get('/posts/{post}', [PostController::class, 'show'])->name('posts.show');
    Route::get('/posts/{post}/edit', [PostController::class, 'edit'])->name('posts.edit');
    Route::put('/posts/{post}', [PostController::class, 'update'])->name('posts.update');
    Route::delete('/posts/{post}', [PostController::class, 'destroy'])->name('posts.destroy');
    Route::post('/posts/{post}/toggle-visibility', [PostController::class, 'toggleVisibility'])->name('posts.toggle-visibility');

    // Comments
    Route::post('/posts/{post}/comments', [CommentController::class, 'store'])->name('comments.store');
    Route::delete('/comments/{comment}', [CommentController::class, 'destroy'])->name('comments.destroy');
    Route::post('/comments/{comment}/toggle-visibility', [CommentController::class, 'toggleVisibility'])->name('comments.toggle-visibility');

    // Likes
    Route::post('/posts/{post}/like', [LikeController::class, 'toggle'])->name('likes.toggle');

    // Reports
    Route::post('/reports', [ReportController::class, 'store'])->name('reports.store');

    // Hunts
    Route::get('/hunts', [HuntController::class, 'index'])->name('hunts.index');
    Route::get('/hunts/create', [HuntController::class, 'create'])->name('hunts.create');
    Route::post('/hunts', [HuntController::class, 'store'])->name('hunts.store');
    Route::get('/hunts/{hunt}', [HuntController::class, 'show'])->name('hunts.show');
    Route::get('/hunts/{hunt}/edit', [HuntController::class, 'edit'])->name('hunts.edit');
    Route::put('/hunts/{hunt}', [HuntController::class, 'update'])->name('hunts.update');
    Route::delete('/hunts/{hunt}', [HuntController::class, 'destroy'])->name('hunts.destroy');
    Route::post('/hunts/{hunt}/refresh-briefing', [HuntController::class, 'refreshBriefing'])->name('hunts.refresh-briefing');
    Route::post('/hunt-checklist/{item}/toggle', [HuntController::class, 'toggleChecklist'])->name('hunts.checklist.toggle');

    // Admin
    Route::prefix('admin')->name('admin.')->middleware('role:admin,moderator')->group(function () {
        Route::get('/', [AdminController::class, 'dashboard'])->name('dashboard');

        Route::middleware('role:admin')->group(function () {
            Route::get('/users', [UserManagementController::class, 'index'])->name('users.index');
            Route::get('/users/{user}/edit', [UserManagementController::class, 'edit'])->name('users.edit');
            Route::put('/users/{user}', [UserManagementController::class, 'update'])->name('users.update');

            Route::get('/roles', [RolePermissionController::class, 'index'])->name('roles.index');
            Route::put('/roles/{role}/permissions', [RolePermissionController::class, 'updatePermissions'])->name('roles.permissions.update');
        });

        Route::get('/reports', [ReportManagementController::class, 'index'])->name('reports.index');
        Route::post('/reports/{report}/review', [ReportManagementController::class, 'review'])->name('reports.review');
    });
});

require __DIR__.'/auth.php';
