<?php

namespace Database\Seeders;

use App\Models\Permission;
use App\Models\Role;
use Illuminate\Database\Seeder;

class RolePermissionSeeder extends Seeder
{
    public function run(): void
    {
        // Create roles
        $admin = Role::create(['name' => 'Admin', 'slug' => 'admin', 'description' => 'Full system access']);
        $mod = Role::create(['name' => 'Moderator', 'slug' => 'moderator', 'description' => 'Content moderation']);
        $member = Role::create(['name' => 'Member', 'slug' => 'member', 'description' => 'Standard member']);

        // Create permissions
        $permissions = [
            // Admin
            ['name' => 'Manage Users', 'slug' => 'manage-users', 'group' => 'admin'],
            ['name' => 'Manage Roles', 'slug' => 'manage-roles', 'group' => 'admin'],
            ['name' => 'Manage Settings', 'slug' => 'manage-settings', 'group' => 'admin'],
            // Moderation
            ['name' => 'Moderate Content', 'slug' => 'moderate-content', 'group' => 'moderation'],
            ['name' => 'Delete Any Post', 'slug' => 'delete-any-post', 'group' => 'moderation'],
            ['name' => 'Delete Any Comment', 'slug' => 'delete-any-comment', 'group' => 'moderation'],
            ['name' => 'Review Reports', 'slug' => 'review-reports', 'group' => 'moderation'],
            // Member
            ['name' => 'Create Post', 'slug' => 'create-post', 'group' => 'content'],
            ['name' => 'Create Hunt', 'slug' => 'create-hunt', 'group' => 'content'],
            ['name' => 'Create Comment', 'slug' => 'create-comment', 'group' => 'content'],
            ['name' => 'Like Post', 'slug' => 'like-post', 'group' => 'content'],
        ];

        foreach ($permissions as $perm) {
            Permission::create($perm);
        }

        // Assign all permissions to admin
        $admin->permissions()->attach(Permission::all());

        // Assign moderation + content permissions to moderator
        $mod->permissions()->attach(
            Permission::whereIn('group', ['moderation', 'content'])->get()
        );

        // Assign content permissions to member
        $member->permissions()->attach(
            Permission::where('group', 'content')->get()
        );
    }
}
</boltAction>

