<boltAction type="file" filePath="app/Models/User.php" contentType="text/x-php">
<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Factories\HasFactory;
use Illuminate\Database\Eloquent\Relations\BelongsToMany;
use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Foundation\Auth\User as Authenticatable;
use Illuminate\Notifications\Notifiable;

class User extends Authenticatable
{
    use HasFactory, Notifiable;

    protected $fillable = [
        'name', 'email', 'password', 'avatar', 'bio', 'location',
    ];

    protected $hidden = ['password', 'remember_token'];

    protected function casts(): array
    {
        return [
            'email_verified_at' => 'datetime',
            'password' => 'hashed',
        ];
    }

    // Relationships
    public function roles(): BelongsToMany
    {
        return $this->belongsToMany(Role::class)->withTimestamps();
    }

    public function directPermissions(): BelongsToMany
    {
        return $this->belongsToMany(Permission::class)->withTimestamps();
    }

    public function posts(): HasMany
    {
        return $this->hasMany(Post::class);
    }

    public function comments(): HasMany
    {
        return $this->hasMany(Comment::class);
    }

    public function likes(): HasMany
    {
        return $this->hasMany(Like::class);
    }

    public function hunts(): HasMany
    {
        return $this->hasMany(Hunt::class);
    }

    public function reports(): HasMany
    {
        return $this->hasMany(Report::class);
    }

    // Role helpers
    public function hasRole(string $slug): bool
    {
        return $this->roles()->where('slug', $slug)->exists();
    }

    public function isAdmin(): bool
    {
        return $this->hasRole('admin');
    }

    public function isModerator(): bool
    {
        return $this->hasRole('moderator') || $this->isAdmin();
    }

    public function hasPermission(string $slug): bool
    {
        // Check direct permissions
        if ($this->directPermissions()->where('slug', $slug)->exists()) {
            return true;
        }

        // Check role-based permissions
        foreach ($this->roles as $role) {
            if ($role->hasPermission($slug)) {
                return true;
            }
        }

        return false;
    }

    public function assignRole(string $slug): void
    {
        $role = Role::where('slug', $slug)->firstOrFail();
        $this->roles()->syncWithoutDetaching([$role->id]);
    }

    public function removeRole(string $slug): void
    {
        $role = Role::where('slug', $slug)->first();
        if ($role) {
            $this->roles()->detach($role->id);
        }
    }

    // Badge helpers
    public function getBadges(): array
    {
        $badges = [];
        $postCount = $this->posts()->count();
        $huntCount = $this->hunts()->count();
        $speciesCount = $this->posts()->whereNotNull('species')->distinct('species')->count('species');
        $likeCount = Like::whereIn('post_id', $this->posts()->pluck('id'))->count();

        if ($postCount >= 1) $badges[] = ['icon' => '🎣', 'label' => 'First Catch', 'color' => 'emerald'];
        if ($postCount >= 5) $badges[] = ['icon' => '🏆', 'label' => '5 Catches', 'color' => 'amber'];
        if ($postCount >= 10) $badges[] = ['icon' => '⭐', 'label' => '10 Catches', 'color' => 'purple'];
        if ($postCount >= 25) $badges[] = ['icon' => '👑', 'label' => 'Catch King', 'color' => 'yellow'];
        if ($speciesCount >= 3) $badges[] = ['icon' => '🐟', 'label' => '3 Species', 'color' => 'blue'];
        if ($speciesCount >= 5) $badges[] = ['icon' => '🐠', 'label' => '5 Species', 'color' => 'cyan'];
        if ($speciesCount >= 10) $badges[] = ['icon' => '🦈', 'label' => 'Species Master', 'color' => 'indigo'];
        if ($huntCount >= 1) $badges[] = ['icon' => '🗺️', 'label' => 'First Hunt', 'color' => 'green'];
        if ($huntCount >= 5) $badges[] = ['icon' => '🧭', 'label' => '5 Hunts', 'color' => 'teal'];
        if ($likeCount >= 10) $badges[] = ['icon' => '❤️', 'label' => 'Popular', 'color' => 'pink'];
        if ($likeCount >= 50) $badges[] = ['icon' => '🔥', 'label' => 'On Fire', 'color' => 'red'];

        return $badges;
    }

    public function hasLiked(Post $post): bool
    {
        return $this->likes()->where('post_id', $post->id)->exists();
    }

    public function getAvatarUrl(): string
    {
        if ($this->avatar) {
            return asset('storage/' . $this->avatar);
        }
        return 'https://ui-avatars.com/api/?name=' . urlencode($this->name) . '&background=9E7FFF&color=fff&size=128';
    }
}
</boltAction>

