            ['name' => 'Pike', 'likelihood' => $month >= 10 || $month <= 3 ? 'High' : 'Medium', 'best_bait' => ['Deadbait', 'Lures', 'Spinnerbait'], 'best_time' => 'Morning', 'min_size_cm' => 0, 'season_note' => 'Peak Oct-Mar, predator season'],
            ['name' => 'Perch', 'likelihood' => 'High', 'best_bait' => ['Worms', 'Maggots', 'Small lures'], 'best_time' => 'Dawn and dusk', 'min_size_cm' => 0, 'season_note' => 'Year-round, best autumn'],
            ['name' => 'Roach', 'likelihood' => 'High', 'best_bait' => ['Maggots', 'Bread punch', 'Hemp'], 'best_time' => 'Afternoon', 'min_size_cm' => 0, 'season_note' => 'Year-round, great for beginners'],
