<boltAction type="file" filePath="app/Services/HuntBriefingService.php" contentType="text/x-php">
<?php

namespace App\Services;

use App\Models\Hunt;
use App\Models\HuntBriefing;
use App\Models\HuntChecklistItem;
use App\Services\Providers\WeatherProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\SpeciesInfoProviderInterface;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\DB;

class HuntBriefingService
{
    public function __construct(
        private WeatherProviderInterface $weatherProvider,
        private TideProviderInterface $tideProvider,
        private SpeciesInfoProviderInterface $speciesProvider,
    ) {}

    public function generateBriefing(Hunt $hunt): HuntBriefing
    {
        $lat = $hunt->latitude ?? 51.5074;
        $lng = $hunt->longitude ?? -0.1278;

        $cacheKey = "hunt_briefing_{$hunt->id}";

        // Check cache
        $cached = Cache::get($cacheKey);
        if ($cached && $hunt->briefing && !$hunt->briefing->isExpired()) {
            return $hunt->briefing;
        }

        // Fetch data from providers
        $weatherData = $this->weatherProvider->getForecast(
            $lat, $lng,
            $hunt->starts_at->toDateTime(),
            $hunt->ends_at->toDateTime()
        );

        $tideData = null;
        if ($hunt->is_coastal) {
            $tideData = $this->tideProvider->getTides(
                $lat, $lng,
                $hunt->starts_at->toDateTime()
            );
        }

        $speciesData = $this->speciesProvider->getSpeciesForLocation(
            $lat, $lng,
            $hunt->starts_at->month,
            $hunt->is_coastal
        );

        $suggestions = $this->generateSuggestions($weatherData, $tideData, $speciesData, $hunt);

        DB::transaction(function () use ($hunt, $weatherData, $tideData, $speciesData, $suggestions) {
            // Create or update briefing
            $hunt->briefing()->updateOrCreate(
                ['hunt_id' => $hunt->id],
                [
                    'weather_data' => $weatherData,
                    'tide_data' => $tideData,
                    'species_data' => $speciesData,
                    'suggestions' => $suggestions,
                    'weather_provider' => $this->weatherProvider->getProviderName(),
                    'tide_provider' => $this->tideProvider->getProviderName(),
                    'species_provider' => $this->speciesProvider->getProviderName(),
                    'fetched_at' => now(),
                    'expires_at' => now()->addHours(6),
                ]
            );

            // Generate checklist items
            $this->generateChecklist($hunt, $weatherData, $tideData, $speciesData, $suggestions);
        });

        Cache::put($cacheKey, true, now()->addHours(6));

        return $hunt->briefing()->first();
    }

    private function generateSuggestions(array $weather, ?array $tides, array $species, Hunt $hunt): array
    {
        $suggestions = [];

        // Timing tips
        $timingTips = [];
        if (!empty($weather['forecast'])) {
            $day = $weather['forecast'][0] ?? null;
            if ($day) {
                $timingTips[] = "Sunrise at {$day['sunrise']}, sunset at {$day['sunset']}";
                if ($day['wind_speed_mph'] > 15) {
                    $timingTips[] = "Strong winds expected ({$day['wind_speed_mph']}mph {$day['wind_direction']}). Seek sheltered spots.";
                }
                if ($day['precipitation_chance'] > 50) {
                    $timingTips[] = "Rain likely ({$day['precipitation_chance']}% chance). Pack waterproofs!";
                }
            }
        }

        if ($tides && !empty($tides['tides'])) {
            foreach ($tides['tides'] as $tide) {
                if ($tide['type'] === 'high') {
                    $timingTips[] = "High tide at {$tide['time']} ({$tide['height_m']}m). Fish 2hrs either side for best results.";
                    break;
                }
            }
            if (!empty($tides['best_fishing'])) {
                $timingTips[] = $tides['best_fishing'];
            }
        }

        $suggestions['timing_tips'] = $timingTips;

        // Recommended tackle
        $tackle = [
            'Essential' => ['Rod rest/bankstick', 'Landing net', 'Unhooking mat', 'Forceps/disgorger'],
            'Terminal tackle' => ['Hooks (sizes 6-2/0)', 'Weights/leads', 'Swivels', 'Line (8-15lb)'],
            'Comfort' => ['Waterproof jacket', 'Warm layers', 'Sunscreen', 'Snacks & drinks'],
            'Safety' => ['First aid kit', 'Phone (charged)', 'Headtorch'],
        ];

        if ($hunt->is_coastal) {
            $tackle['Sea fishing'] = ['Long-range rod (12ft+)', 'Multiplier or large fixed spool reel', 'Rig wallet', 'Bait bucket', 'Grip leads for rough ground'];
        } else {
            $tackle['Freshwater'] = ['Rod (10-12ft float or feeder)', 'Reel with 6-10lb line', 'Float selection', 'Feeders', 'Groundbait'];
        }

        $suggestions['tackle'] = $tackle;

        // Species-specific bait suggestions
        $baitSuggestions = [];
        if (!empty($species['species'])) {
            foreach ($species['species'] as $sp) {
                if (in_array($sp['likelihood'], ['High', 'Medium'])) {
                    $baitSuggestions[] = [
                        'species' => $sp['name'],
                        'baits' => $sp['best_bait'],
                        'best_time' => $sp['best_time'],
                    ];
                }
            }
        }
        $suggestions['bait_suggestions'] = $baitSuggestions;

        return $suggestions;
    }

    private function generateChecklist(Hunt $hunt, array $weather, ?array $tides, array $species, array $suggestions): void
    {
        // Remove existing auto-generated items (keep user-added ones if we add that feature later)
        $hunt->checklistItems()->delete();

        $items = [];
        $order = 0;

        // Essential gear
        $essentials = ['Rod & reel', 'Landing net', 'Unhooking mat/forceps', 'Tackle box', 'Bait', 'Rod licence (if freshwater)'];
        foreach ($essentials as $item) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Essential Gear', 'label' => $item, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        // Weather-based items
        if (!empty($weather['forecast'][0])) {
            $day = $weather['forecast'][0];
            if ($day['precipitation_chance'] > 30) {
                $items[] = ['hunt_id' => $hunt->id, 'category' => 'Weather Prep', 'label' => 'Waterproof jacket & trousers', 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
            }
            if ($day['temp_low_c'] < 12) {
                $items[] = ['hunt_id' => $hunt->id, 'category' => 'Weather Prep', 'label' => 'Warm layers / thermal base', 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
            }
            if ($day['temp_high_c'] > 18) {
                $items[] = ['hunt_id' => $hunt->id, 'category' => 'Weather Prep', 'label' => 'Sunscreen & hat', 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
            }
            if ($day['wind_speed_mph'] > 15) {
                $items[] = ['hunt_id' => $hunt->id, 'category' => 'Weather Prep', 'label' => 'Windproof shelter / brolly', 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
            }
        }

        // Bait items from species suggestions
        $baitsAdded = [];
        if (!empty($species['species'])) {
            foreach ($species['species'] as $sp) {
                if (in_array($sp['likelihood'], ['High', 'Medium'])) {
                    foreach ($sp['best_bait'] as $bait) {
                        if (!in_array($bait, $baitsAdded)) {
                            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Bait & Lures', 'label' => $bait, 'notes' => "For {$sp['name']}", 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
                            $baitsAdded[] = $bait;
                        }
                    }
                }
            }
        }

        // Comfort & safety
        $comfort = ['Food & drinks', 'Chair / seat box', 'Phone (fully charged)', 'Headtorch / lamp', 'First aid kit'];
        foreach ($comfort as $item) {
            $items[] = ['hunt_id' => $hunt->id, 'category' => 'Comfort & Safety', 'label' => $item, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
        }

        // Coastal specific
        if ($hunt->is_coastal) {
            $coastalItems = ['Tide timetable (printed backup)', 'Grip leads', 'Long casting rod', 'Bait bucket with lid'];
            foreach ($coastalItems as $item) {
                $items[] = ['hunt_id' => $hunt->id, 'category' => 'Sea Fishing', 'label' => $item, 'sort_order' => $order++, 'created_at' => now(), 'updated_at' => now()];
            }
        }

        HuntChecklistItem::insert($items);
    }
}
