namespace App\Http\Controllers;

use App\Models\Post;
use Illuminate\Http\Request;

class FeedController extends Controller
{
    public function index(Request $request)
    {
        $query = Post::with(['user', 'images', 'likes', 'comments'])
            ->where('is_visible', true)
            ->orderBy('created_at', 'desc');

        // Filters
        if ($request->filled('species')) {
            $query->where('species', 'ilike', '%' . $request->species . '%');
        }

        if ($request->filled('location')) {
            $query->where('location_name', 'ilike', '%' . $request->location . '%');
        }

        if ($request->filled('date_from')) {
            $query->where('caught_at', '>=', $request->date_from);
        }

        if ($request->filled('date_to')) {
            $query->where('caught_at', '<=', $request->date_to . ' 23:59:59');
        }

        $posts = $query->paginate(12);

        if ($request->ajax()) {
            return view('feed._posts', compact('posts'));
        }

        $speciesList = Post::where('is_visible', true)
            ->whereNotNull('

species')
            ->distinct()
            ->pluck('species')
            ->sort()
            ->values();

        return view('feed.index', compact('posts', 'speciesList'));
    }
}
