class ProfileController extends Controller
{
    public function show(User $user)
    {
        $posts = $user->posts()
            ->where('is_visible', true)
            ->with(['images', 'likes', 'comments'])
            ->orderBy('created_at', 'desc')
            ->paginate(12);

        $hunts = $user->hunts()
            ->where('is_public', true)
            ->orderBy('starts_at', 'desc')
            ->limit(6)
            ->get();

        $badges = $user->getBadges();

        $stats = [
            'catches' => $user->posts()->count(),
            'species' => $user->posts()->whereNotNull('species')->distinct('species')->count('species'),
            'hunts' => $user->hunts()->count(),
            'likes_received' => \App\Models\Like::whereIn('post_id', $user->posts()->pluck('id'))->count(),
        ];

        return view('profile.show', compact('user', 'posts', 'hunts', 'badges', 'stats'));
