<?php

namespace App\Http\Controllers\Admin;

use App\Http\Controllers\Controller;
use App\Models\Report;
use Illuminate\Http\Request;

class ReportManagementController extends Controller
{
    public function index(Request $request)
    {
        $query = Report::with(['user', 'reportable', 'reviewer'])
            ->orderBy('created_at', 'desc');

        if ($request->filled('status')) {
            $query->where('status', $request->status);
        } else {
            $query->where('status', 'pending');
        }

        $reports = $query->paginate(20);

        return view('admin.reports.index', compact('reports'));
    }

    public function review(Request $request, Report $report)
    {
        $validated = $request->validate([
            'status' => 'required|in:reviewed,dismissed,actioned',
            'review_notes' => 'nullable|string|max:2000',
            'hide_content' => 'boolean',
        ]);

        $report->update([
            'status' => $validated['status'],
            'review_notes' => $validated['review_notes'] ?? null,
            'reviewed_by' => $request->user()->id,
        ]);

        // Optionally hide the reported content
        if ($request->boolean('hide_content') && $report->reportable) {
            $report->reportable->update(['is_visible' => false]);
        }

        return back()->with('success', 'Report reviewed.');
    }
}
</boltAction>

